from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    if not triples:
        return ""

    # Helper to lower‑case genre/style names for natural phrasing
    def lc(text: str) -> str:
        return text.lower()

    # Index triples by subject for quick lookup
    from collections import defaultdict, OrderedDict

    subj_map: dict[str, list[Triple]] = defaultdict(list)
    order: list[str] = []  # preserve first‑seen subject order
    for t in triples:
        subj_map[t.subject].append(t)
        if t.subject not in order:
            order.append(t.subject)

    sentences: list[str] = []

    for subj in order:
        parts: list[str] = []
        triples_here = subj_map[subj]

        # ----- genre handling (with possible stylisticOrigin of the genre) -----
        genre_triples = [t for t in triples_here if t.predicate == "genre"]
        if genre_triples:
            genre_obj = genre_triples[0].object
            phrase = f"{subj} plays {lc(genre_obj)} music"
            # look for a triple where the genre is the subject and has stylisticOrigin
            for t in triples:
                if t.subject == genre_obj and t.predicate == "stylisticOrigin":
                    phrase += f", which originated from {lc(t.object)}"
                    break
            parts.append(phrase)

        # ----- associated band / musical artist -----
        assoc = [t for t in triples_here if t.predicate == "associatedBand/associatedMusicalArtist"]
        if assoc:
            # collect all associated bands/artists and join with commas and 'and'
            bands = [t.object for t in assoc]
            if len(bands) == 1:
                band_phrase = bands[0]
            else:
                band_phrase = ", ".join(bands[:-1]) + " and " + bands[-1]
            parts.append(f"{subj} is associated with {band_phrase}")

        # ----- basic personal info -----
        for t in triples_here:
            s, p, o = t.subject, t.predicate, t.object
            if p in ("birthDate", "birthYear"):
                parts.append(f"{subj} was born in {o}")
            elif p in ("deathDate", "deathPlace"):
                parts.append(f"{subj} died in {o}")
            elif p == "birthPlace":
                parts.append(f"{subj} was born in {o}")
            elif p == "origin":
                parts.append(f"{subj} originates from {o}")
            elif p == "instrument":
                parts.append(f"{subj} plays the {o}")
            elif p == "occupation":
                parts.append(f"{subj} works as {o}")
            elif p == "nationality":
                parts.append(f"{subj} is {o}")
            elif p == "recordLabel":
                # Use a more natural phrasing that includes the descriptor "record label"
                parts.append(f"{subj} is signed to the record label {o}")
            elif p == "background":
                parts.append(f"{subj} has a background as {o}")
            elif p == "activeYearsStartYear":
                parts.append(f"{subj} started activity in {o}")
            elif p == "activeYearsEndYear":
                parts.append(f"{subj} ended activity in {o}")

        # ----- relational predicates where object is primary -----
        # Custom phrasing for different predicates to produce natural language.
        # Mapping of predicates to phrasing and direction.
        # direction = True  -> object first (object phr subject)
        # direction = False -> subject first (subject phr object)
        object_primary_predicates = {
            "leader": ("is the leader of", True),
            "capital": ("is the capital of", True),
            "currency": ("uses the currency", True),
            "anthem": ("has the anthem", True),
            "parentCompany": ("is owned by", True),
            "location": ("is located in", True),
            "governingBody": ("is governed by", True),
            "leaderTitle": ("holds the title", True),
            "country": ("is part of", False),          # Montevideo is part of Uruguay
            "isPartOf": ("is part of", False),         # Asunción is part of Gran Asunción
            "derivative": ("is a form of", True),      # e.g., Synthpop is a form of House music
            "bandMember": ("has band member", False),
            "musicFusionGenre": ("is a music fusion genre of", False),
            "musicSubgenre": ("is a music subgenre of", False),
            "stylisticOrigin": ("has stylistic origin in", False)
        }
        for t in triples_here:
            if t.predicate in object_primary_predicates:
                phr, obj_first = object_primary_predicates[t.predicate]
                if obj_first:
                    parts.append(f"{t.object} {phr} {subj}")
                else:
                    parts.append(f"{subj} {phr} {t.object}")

        # Combine parts for this subject
        if parts:
            if len(parts) == 1:
                sentences.append(parts[0] + ".")
            else:
                sentences.append(", ".join(parts[:-1]) + ", and " + parts[-1] + ".")

    # Join sentences for different subjects
    return " ".join(sentences)

# EVOLVE-BLOCK-END
